{
  "original_problem_summary": "Find the product of the real roots of the equation $x^2 + 18x + 30 = 2 \\sqrt{x^2 + 18x + 45}$.",
  "variants": [
    {
      "variant_id": "var_001",
      "problem": "What is the product of the real roots of the equation $x^2 - 16x + 50 = \\sqrt{x^2 - 16x + 56}$?",
      "solution": "Let $u = \\sqrt{x^2 - 16x + 56}$. Then $x^2 - 16x + 50 = u^2 - 6$. Substituting this into the original equation, we get $u^2 - 6 = u$, which rearranges to $u^2 - u - 6 = 0$. Factoring the quadratic gives $(u-3)(u+2) = 0$. Since $u$ must be a non-negative real number (as it is a square root), we must have $u = 3$. Thus, $x^2 - 16x + 56 = 3^2 = 9$, which simplifies to $x^2 - 16x + 47 = 0$. The discriminant of this quadratic is $D = (-16)^2 - 4(1)(47) = 256 - 188 = 68 > 0$, so both roots are real. By Vieta's Formulas, the product of the roots is the constant term. Final answer is \\boxed{47}.",
      "variant_reasoning": "This variant simplifies the coefficient of the radical and adjusts the constants to maintain the core substitution method while ensuring integer results."
    },
    {
      "variant_id": "var_002",
      "problem": "What is the product of the real roots of the equation $x^2 - 30x + 200 = 4\\sqrt{x^2 - 30x + 205}$?",
      "solution": "Let $u = \\sqrt{x^2 - 30x + 205}$. Then $x^2 - 30x + 200 = u^2 - 5$. Substituting this into the original equation, we get $u^2 - 5 = 4u$, or $u^2 - 4u - 5 = 0$. Factoring yields $(u-5)(u+1) = 0$. Since $u \\ge 0$, we have $u = 5$. Then $x^2 - 30x + 205 = 5^2 = 25$, so $x^2 - 30x + 180 = 0$. The discriminant is $D = 30^2 - 4(180) = 900 - 720 = 180 > 0$, so the roots are real. By Vieta's Formulas, the product of these roots is \\boxed{180}.",
      "variant_reasoning": "This variant uses a larger multiplier for the radical and larger constants, testing the solver's ability to handle slightly more complex quadratic factoring."
    },
    {
      "variant_id": "var_003",
      "problem": "Find the product of the real roots of the equation $x + \\frac{10}{x} - 8 = \\sqrt{x + \\frac{10}{x} - 2}$.",
      "solution": "Let $u = \\sqrt{x + \\frac{10}{x} - 2}$. Then $x + \\frac{10}{x} - 8 = u^2 - 6$. The equation becomes $u^2 - 6 = u$, so $u^2 - u - 6 = 0$. Factoring gives $(u-3)(u+2) = 0$. Since $u \\ge 0$, $u = 3$. Then $x + \\frac{10}{x} - 2 = 9$, so $x + \\frac{10}{x} - 11 = 0$. Multiplying by $x$ gives $x^2 - 11x + 10 = 0$. The discriminant $D = 121 - 40 = 81 > 0$, so the roots are real. By Vieta's Formulas, the product of the roots is \\boxed{10}.",
      "variant_reasoning": "By changing the expression from a quadratic in $x$ to a rational function $x + a/x$, the problem requires an additional step of multiplying through by $x$ to find the final product."
    },
    {
      "variant_id": "var_004",
      "problem": "Find the sum of the squares of the real roots of the equation $x^2 - 4x - 2 = \\sqrt{x^2 - 4x + 4}$.",
      "solution": "Let $u = \\sqrt{x^2 - 4x + 4} = |x-2|$. The equation is $x^2 - 4x - 2 = u$. Since $x^2 - 4x + 4 = u^2$, we have $x^2 - 4x = u^2 - 4$. Substituting this in, we get $u^2 - 4 - 2 = u$, so $u^2 - u - 6 = 0$. Factoring gives $(u-3)(u+2) = 0$. Since $u \\ge 0$, $u = 3$. This means $|x-2| = 3$, so $x-2 = 3$ or $x-2 = -3$. The roots are $x = 5$ and $x = -1$. The sum of the squares of the roots is $5^2 + (-1)^2 = 25 + 1 = \\boxed{26}.",
      "variant_reasoning": "This variant asks for a different property (sum of squares) and uses a perfect square under the radical to introduce an absolute value interpretation."
    },
    {
      "variant_id": "var_005",
      "problem": "Find the product of the real roots of the equation $(x^2 - 4)^2 - 5(x^2 - 4) + 2 = 2\\sqrt{(x^2 - 4)^2 - 5(x^2 - 4) + 5}$.",
      "solution": "Let $w = (x^2 - 4)^2 - 5(x^2 - 4)$. The equation is $w + 2 = 2\\sqrt{w + 5}$. Squaring both sides, $w^2 + 4w + 4 = 4(w + 5) = 4w + 20$. This simplifies to $w^2 = 16$, so $w = 4$ or $w = -4$. However, for the original equation to hold, $w+2$ must be non-negative, so $w=4$. Then $(x^2 - 4)^2 - 5(x^2 - 4) - 4 = 0$. Let $v = x^2 - 4$, so $v^2 - 5v - 4 = 0$. The roots for $v$ are $v = \\frac{5 \\pm \\sqrt{41}}{2}$. Then $x^2 = v + 4 = \\frac{5 \\pm \\sqrt{41}}{2} + 4 = \\frac{13 \\pm \\sqrt{41}}{2}$. Both values are positive since $\\sqrt{41} < 13$. The four roots are $x = \\pm \\sqrt{\\frac{13 + \\sqrt{41}}{2}}$ and $x = \\pm \\sqrt{\\frac{13 - \\sqrt{41}}{2}}$. Their product is $\\left(-\\frac{13 + \\sqrt{41}}{2}\\right) \\left(-\\frac{13 - \\sqrt{41}}{2}\\right) = \\frac{169 - 41}{4} = \\frac{128}{4} = \\boxed{32}.",
      "variant_reasoning": "This variant increases the difficulty by using a quartic expression as the inner function, leading to four real roots whose product must be calculated."
    },
    {
      "variant_id": "var_006",
      "problem": "Find the product of the distinct real roots of the equation $x^2 - 12x + 31 = \\frac{10}{x^2 - 12x + 34}$.",
      "solution": "Let $y = x^2 - 12x + 31$. Then the equation is $y = \\frac{10}{y + 3}$, which gives $y^2 + 3y - 10 = 0$. Factoring, we get $(y+5)(y-2) = 0$, so $y = 2$ or $y = -5$. Case 1: $x^2 - 12x + 31 = 2 \\Rightarrow x^2 - 12x + 29 = 0$. The discriminant is $144 - 4(29) = 28 > 0$, so there are two real roots with product 29. Case 2: $x^2 - 12x + 31 = -5 \\Rightarrow x^2 - 12x + 36 = 0 \\Rightarrow (x-6)^2 = 0$. This gives the single root $x=6$. The distinct real roots are $6 + \\sqrt{7}, 6 - \\sqrt{7},$ and $6$. Their product is $(36 - 7) \\cdot 6 = 29 \\cdot 6 = \\boxed{174}.",
      "variant_reasoning": "This variant replaces the radical with a rational function, leading to multiple cases for the inner quadratic and requiring the product of distinct roots."
    },
    {
      "variant_id": "var_007",
      "problem": "Find the sum of the real roots of the equation $x^2 - 100x + 2400 = 10\\sqrt{x^2 - 100x + 2424}$.",
      "solution": "Let $u = \\sqrt{x^2 - 100x + 2424}$. Then $x^2 - 100x + 2400 = u^2 - 24$. The equation is $u^2 - 24 = 10u$, or $u^2 - 10u - 24 = 0$. Factoring gives $(u-12)(u+2) = 0$. Since $u \\ge 0$, $u = 12$. Thus $x^2 - 100x + 2424 = 144$, so $x^2 - 100x + 2280 = 0$. The discriminant is $10000 - 4(2280) = 880 > 0$. By Vieta's Formulas, the sum of the roots is \\boxed{100}.",
      "variant_reasoning": "This variant uses significantly larger coefficients and asks for the sum of the roots instead of the product, providing variety while maintaining the same structural logic."
    },
    {
      "variant_id": "var_008",
      "problem": "Find the product of the real roots of the equation $x^2 - 22x + 110 = 2\\sqrt{x^2 - 22x + 113}$.",
      "solution": "Let $u = \\sqrt{x^2 - 22x + 113}$. Then $x^2 - 22x + 110 = u^2 - 3$. The equation is $u^2 - 3 = 2u$, or $u^2 - 2u - 3 = 0$. Factoring gives $(u-3)(u+1) = 0$. Since $u \\ge 0$, $u = 3$. Thus $x^2 - 22x + 113 = 9$, which simplifies to $x^2 - 22x + 104 = 0$. The discriminant is $22^2 - 4(104) = 484 - 416 = 68 > 0$. By Vieta's Formulas, the product of the roots is \\boxed{104}.",
      "variant_reasoning": "This variant follows the exact structure of the original but with different numerical values to check for computational accuracy and understanding of the substitution process."
    },
    {
      "variant_id": "var_009",
      "problem": "What is the product of the real roots of the equation $\\sqrt{x^2 - 4x + 11} + \\sqrt{x^2 - 4x + 6} = 5$?",
      "solution": "Let $y = x^2 - 4x + 6$. Then the equation is $\\sqrt{y+5} + \\sqrt{y} = 5$. Subtracting $\\sqrt{y}$ and squaring both sides gives $y+5 = (5 - \\sqrt{y})^2 = 25 + y - 10\\sqrt{y}$. This simplifies to $10\\sqrt{y} = 20$, so $\\sqrt{y} = 2$ and $y = 4$. Substituting back, $x^2 - 4x + 6 = 4$, so $x^2 - 4x + 2 = 0$. The discriminant is $16 - 8 = 8 > 0$. By Vieta's Formulas, the product of the roots is \\boxed{002}.",
      "variant_reasoning": "This variant uses a double radical structure, which can be solved with a similar substitution ($y = x^2 + bx + c$), exploring a slightly different algebraic path to the same core quadratic logic."
    },
    {
      "variant_id": "var_010",
      "problem": "Find the product of the distinct real roots of the equation $|x^2 - 10x + 20| = 2\\sqrt{x^2 - 10x + 20}$.",
      "solution": "Let $u = \\sqrt{x^2 - 10x + 20}$. The equation is $|u^2| = 2u$. Since $u$ is a square root, $u \\ge 0$, so $u^2 = 2u$. This gives $u^2 - 2u = 0$, so $u(u-2) = 0$. This implies $u = 0$ or $u = 2$. If $u = 0$, then $x^2 - 10x + 20 = 0$, which has roots $x = 5 \\pm \\sqrt{5}$ (product 20). If $u = 2$, then $u^2 = 4$, so $x^2 - 10x + 20 = 4$, which means $x^2 - 10x + 16 = 0$. This has roots $x = 8, 2$ (product 16). All four roots are distinct and real. The product of these roots is $20 \\cdot 16 = \\boxed{320}.",
      "variant_reasoning": "This variant incorporates an absolute value and asks for the product of all distinct roots, requiring the solver to handle two different valid values for the substitution variable."
    }
  ]
}
